import { useState, useRef } from 'react'
import style from './style.module.css'
import introVideo from './../assets/media/curtain_video.mp4'

function IntroSlide() {

    const videoRef = useRef()
    const [showContent, setShowContent] = useState(false)

    const handleVideoClick = () => {
        const video = videoRef.current;
        if (video) {
            if (video.paused) {
                video.play()
                setTimeout(() => setShowContent(true), 2000)
                
            }
        }
    }

    return (
        <>
            {showContent ?
                <>
                    <div className={style.introContainer}>
                        <div>
                            <p>We're getting married</p>

                            <h1>
                                <span>Ahmed</span>
                                <span>&</span>
                                <span>Nehal</span>
                            </h1>
                        </div>

                        <div class="flex items-center justify-center gap-4 mb-4" style="opacity: 1;">
                            <span class="h-px bg-white/70 w-12 md:w-24"></span>
                            <span class="text-white text-xl drop-shadow-lg">✦</span>
                            <span class="h-px bg-white/70 w-12 md:w-24"></span>
                        </div>
                    </div>
                    
                    <div className={style.overlay}></div>
                </>
                :
                <>
                    {/* <div>
                        <video 
                            ref={videoRef}
                            className={style.introVideo} 
                            src={introVideo} 
                            onClick={handleVideoClick}
                            controls={false}
                        />
                    </div> */}
                </>
            }
        </>
    )
}

export default IntroSlide
